import{_ as a,o,c as r,a4 as t}from"./chunks/framework.Bv6IB9yN.js";const m=JSON.parse('{"title":"About labs","description":"This page gives on overview of lab management in HUNT Cloud.","frontmatter":{"title":"About labs","category":"HUNT Cloud","permalink":"/administer-science/start-here/labs","outline":0,"description":"This page gives on overview of lab management in HUNT Cloud."},"headers":[],"relativePath":"administer-science/start-here/labs.md","filePath":"administer-science/start-here/labs.md"}'),n={name:"administer-science/start-here/labs.md"};function i(s,e,c,l,h,d){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="about-your-lab" tabindex="-1">About your lab <a class="header-anchor" href="#about-your-lab" aria-label="Permalink to &quot;About your lab&quot;">​</a></h1><p><strong>The digital lab is where your team store and analyze your data.</strong></p><nav class="table-of-contents"><ul><li><a href="#located-in-norway">Located in Norway</a></li><li><a href="#made-for-collaboration">Made for collaboration</a></li><li><a href="#entry-machine-for-security">Entry machine for security</a></li><li><a href="#home-machine-for-science">Home machine for science</a></li><li><a href="#read-more">Read more</a></li></ul></nav><h3 id="located-in-norway" tabindex="-1">Located in Norway <a class="header-anchor" href="#located-in-norway" aria-label="Permalink to &quot;Located in Norway&quot;">​</a></h3><p>Technically, your lab consists of virtual machines that holds security configurations and user management controls, as well as resources for data storage and computation, and software for scientific analysis. Your virtual machines runs on runs on physical servers that are owned by NTNU and located in data centers in Trondheim, Norway.</p><h3 id="made-for-collaboration" tabindex="-1">Made for collaboration <a class="header-anchor" href="#made-for-collaboration" aria-label="Permalink to &quot;Made for collaboration&quot;">​</a></h3><p>Your scientists, that we call &quot;lab users&quot;, gets their own workbench and personal folders inside your lab. Principally, all resources in your lab are shared among your team. This means that lab users can access each others data and review each others code. However, your resources are dedicated to your lab, so your lab users can -not- access resources or data from lab users in other labs in HUNT Cloud.</p><p>By default, your lab consist of two machines, an entry machine and a home machine.</p><h3 id="entry-machine-for-security" tabindex="-1">Entry machine for security <a class="header-anchor" href="#entry-machine-for-security" aria-label="Permalink to &quot;Entry machine for security&quot;">​</a></h3><p>The entry machine is a machine that we have set up to control the security and access to your lab. Your team has to pass this machine to enter your lab. However, they should only see and feel this machine during their user onboarding process.</p><p>The advantages of the entry machine is that we can manage and maintain the security in your lab, including required machine restarts, without affecting your scientific analysis that runs inside your lab.</p><h3 id="home-machine-for-science" tabindex="-1">Home machine for science <a class="header-anchor" href="#home-machine-for-science" aria-label="Permalink to &quot;Home machine for science&quot;">​</a></h3><p>The next machine to know about is your &quot;home machine&quot;. This is were all the fun happens. You home machine holds your default storage volumes, your Workbench tools and your analytical software.</p><p>Note that you can add more machines for increased flexibility whenever you like. You can also upgrade the size of your home machine to get more computational power, and you can add more storage when your projects grow. Such changes are ordered in our administer science service desk.</p><h3 id="read-more" tabindex="-1">Read more <a class="header-anchor" href="#read-more" aria-label="Permalink to &quot;Read more&quot;">​</a></h3><ul><li><a href="/administer-science/service-desk/lab-orders">Administer science service desk</a> list potential lab upgrades.</li></ul>',16)])])}const y=a(n,[["render",i]]);export{m as __pageData,y as default};
